\label{lem:approxconvex}If $F:\mathbb{R}\to\mathbb{R}_{\geq 0}$ satisfies $F(0)=0$ and
  $F''=c_{1}\delta_{0}$ with some $c_{1}\ge 0$, then there
  is a family~$F_{\varepsilon}\in\mathcal{C}^{2}(\mathbb{R})$
  of convex functions   that has the following properties:
  \begin{enumerate}
  \item There is a constant $C<\infty$ so that for all $\varepsilon \in (0, 1]$ and $x \in \mathbb{R}$, we have
    \begin{align}
    &  F_{\varepsilon}(x)       \le C(|x| + \varepsilon),\label{eq:Fbd}                           \\
     & |xF_{\varepsilon}'(x)|   \le CF_{\varepsilon}(x),\label{eq:Fprimebd}                   \\
     & |F_{\varepsilon}'(x)|    \le C,\label{eq:Fepsprimebounded}                      \\
     & |x|F_{\varepsilon}''(x)  \le C\mathbf{1}_{[0,\varepsilon]}(x).\label{eq:Fprimeprimebd}
    \end{align}
  \item The restriction $F_{\varepsilon}|_{\mathbb{R}\setminus[-1,1]}$ is independent
    of $\varepsilon$.
  \item We have
    \begin{equation}
      \lim_{\varepsilon\to0}\|F_{\varepsilon}-F\|_{\mathcal{C}_{\mathrm{b}}(\mathbb{R})}=0.\label{eq:FepstoF}
    \end{equation}
  \end{enumerate}

