Let $m\in(0,1)$ and $\nu\in\overline{\mathscr{P}}(\mathcal{X}_{m}^{2})$.
  Let $\mathbf{v}=(v_{1},v_{2})\sim\nu$ and suppose that one of the
  following two conditions holds:
  \begin{enumerate}[leftmargin = 1.5cm, label = \textup{(H\arabic*)}, ref = (\textup{H\arabic*})]
  \item \label{enu:hyp-stat}
    $\nu\in\overline{\mathscr{P}}_{G}(\mathcal{X}_{m}^{2})$
    for $G=L\mathbb{Z}$ with some $L>0$ or $G=\mathbb{R}$, and
    \begin{equation}\label{jun2518}
      A = \sup\limits_{i\in\{1,2\}} \mathbb{E} \int_{\Lambda_G} v_{i}(x)^{2} \, {d}\lambda_G(x) < \infty.
    \end{equation}
  \item \label{enu:hyp-L1}$\|v_{1}-v_{2}\|_{L^{1}(\mathbb{R})}<\infty$
    almost surely.
  \end{enumerate}
  Then, almost surely, $\operatorname{sgn}(v_{1}(x)-v_{2}(x))$ is a random constant independent
  of $x$.

